INSERT INTO `competitions` (`id`, `name`, `city_name`, `country_id`, `information`, `year`, `month`, `day`, `end_year`, `end_month`, `end_day`, `cancelled`, `event_specs`, `delegates`, `organizers`, `venue`, `venue_address`, `venue_details`, `external_website`, `cell_name`, `latitude_microdegrees`, `longitude_microdegrees`)
VALUES
	('AlbanianOpen2022', 'Albanian Open 2022', 'Tirana', 'Albania', 'Third WCA competition in Albania.\r\n\r\nAdditional [Covid safety measures](https://www.worldcubeassociation.org/competitions/AlbanianOpen2022#-safety-protocol) will be applicable.\r\n', 2022, 6, 25, 2022, 6, 25, 0, '222 333 333bf 444 555 pyram skewb', '[{Aleksandar Arsovski}{mailto:aarsovski@worldcubeassociation.org}] [{Ron van Bruchem}{mailto:rbruchem@worldcubeassociation.org}] [{Samuel Mema}{mailto:samuelmema33@gmail.com}]', '[{Ron van Bruchem}{mailto:rbruchem@worldcubeassociation.org}] [{Samuel Mema}{mailto:samuelmema33@gmail.com}]', '[POLIS University](http://www.universitetipolis.edu.al/)', 'Rruga Bylis 12, Autostrada Tiranë-Durrës, Km 5, Kashar, SH2, Tiranë 1051', 'Room C1', NULL, 'Albanian Open 2022', 41352688, 19750510),
	('CambodiaCubingChampionship2019', 'Cambodia Cubing Championship 2019', 'Phnom Penh', 'Cambodia', 'This is the first-ever national cubing championship of Cambodia.\r\nWe also have a Facebook groups for our Cubing Area. [Khmer Top Cuber](https://www.facebook.com/groups/KhmerCuber/). You can join the group to stay updated with upcoming competitions in the area.', 2019, 11, 3, 2019, 11, 3, 0, '222 333 333oh 444 pyram skewb sq1', '[{John Edison Ubaldo (ᜇ᜔ᜌᜓ︀ᜈ᜔ ᜁᜇᜒᜐᜓ︀ᜈ᜔ ᜂᜊᜎ᜔ᜇᜓ︀)}{mailto:jubaldo@worldcubeassociation.org}]', '[{Mey Samorn}{mailto:samornreality@gmail.com}]', '[Cambodia-Japan Cooperation Center](http://www.cjcc.edu.kh/site/index.php/en/)', 'Russian Confederation Blvd., Tuol Kork, Pnom Penh, Cambodia', 'Angkor Kizuna Hall', NULL, 'Cambodia Championship 2019', 11568929, 104893694),
	('CubanOpen2016', 'Cuban Open 2016', 'Habana', 'Cuba', '', 2016, 4, 9, 2016, 4, 9, 0, '222 333 333oh 444', '[{Ron van Bruchem}{mailto:rbruchem@worldcubeassociation.org}]', '[{Andy Valdes}{mailto:andyvaldes1991@gmail.com}] [{Hanneke Rijks}{mailto:hannekerijks@hotmail.com}] [{Ron van Bruchem}{mailto:rbruchem@worldcubeassociation.org}]', 'Casa Valdes', 'Zona 8 Alamar, La Habana', 'Edif. D-49 Apto.12', 'http://speedcubing.com/events/CubanOpen2016', 'Cuban Open 2016', 23081275, -82302783),
	('CubingReturnsToColombo2022', 'Cubing Returns To Colombo 2022', 'Colombo', 'Sri Lanka', '* Make sure you will be available at the venue at least 15 minutes before your event starts. You won\'t be allowed to participate in an event if you reach late. You can refer \"Schedule\" tab to see the starting time of each event.\r\n* If you\'re participating in a WCA competition for the first time or not aware of competition rules, make sure that you attend the tutorial session at 10:15 a.m on Day 2 (25-Sep-2022)\r\n* If you\'re participating in a WCA competition for the first time, please bring your ID card as well. (NIC/Passport/Postal ID/Driving License)\r\n* All participants are expected to volunteer for the event when they are not participating. The roles could be of a judge, runner, or a scrambler, depending upon the situation.\r\n\r\nCOVID-19 Specific Information:\r\n\r\n* Following all local goverment health guidelines is mandatory while attending the competition. \r\n* We strongly recommend limiting the number of guests you bring for the safety of all attendees. The maximum number of guests that is preferred to accompay a competitor would be limited to TWO.\r\n', 2022, 9, 24, 2022, 9, 25, 0, '222 333 333bf 333fm 444 666 clock pyram skewb', '[{Sachin Arvind}{mailto:sarvind@worldcubeassociation.org}]', '[{Kalindu Sachintha Wijesundara}{mailto:kalindu.sachintha@gmail.com}]', 'Mahanama College', 'Mahanama College, R. A. D. Mel Mawatha, Colombo 3, Sri Lanka', 'Auditorium', NULL, 'Cubing Colombo 2022', 6906181, 79854769),
	('FMC2020', 'FMC 2020', 'Multiple Cities', 'XW', '# The competition has been cancelled due to the COVID-19 outbreak.\r\nThe competition will be held in multiple locations, across the globe. Please pay attention to the **date and time zone** of your location!\r\n\r\nLocations may be added until the 13th of May 23:59UTC so if there isn\'t a location near you yet contact your local [Delegate](https://www.worldcubeassociation.org/delegates).', 2020, 6, 13, 2020, 6, 14, 1, '333fm', '[{Akash Rupela}{mailto:arupela@worldcubeassociation.org}] [{Baiqiang Dong (董百强)}{mailto:bdong@worldcubeassociation.org}] [{Ethan Pride}{mailto:epride@worldcubeassociation.org}] [{Kit Clement}{mailto:kclement@worldcubeassociation.org}] [{Philippe Virouleau}{mailto:pvirouleau@worldcubeassociation.org}]', '[{Akash Rupela}{mailto:arupela@worldcubeassociation.org}] [{Baiqiang Dong (董百强)}{mailto:bdong@worldcubeassociation.org}] [{Callum James Goodyear}{mailto:cgoodyear@worldcubeassociation.org}] [{Ethan Pride}{mailto:epride@worldcubeassociation.org}] [{Kit Clement}{mailto:kclement@worldcubeassociation.org}] [{Philippe Virouleau}{mailto:pvirouleau@worldcubeassociation.org}] [{Theo Daniel Gallegos Cuevas}{mailto:theogallegos88@gmail.com}]', 'Multiple Cities', 'Multiple Locations', 'See the locations tab for more information about venue locations', NULL, 'FMC 2020', 0, 0),
	('FMCAsia2019', 'FMC Asia 2019', 'Multiple cities (see website)', 'XA', '**YOU MUST INCLUDE THE LOCATION YOU ARE ATTENDING IN YOUR REGISTRATION COMMENT.**\r\n\r\nThe competition will be held in multiple locations, Asia. Please pay attention to the **date and time zone** of your location!\r\n\r\nLocations may be added until the 9th of November 23:59 UTC so if there isn\'t a location near you yet contact your local [Delegate](https://www.worldcubeassociation.org/delegates) in Asia.', 2019, 12, 7, 2019, 12, 7, 0, '333fm', '[{Akash Rupela}{mailto:arupela@worldcubeassociation.org}] [{Aysha Jamsheer}{mailto:ajamsheer@worldcubeassociation.org}] [{Baiqiang Dong (董百强)}{mailto:bdong@worldcubeassociation.org}] [{Baocheng Wu (吴宝城)}{mailto:bwu@worldcubeassociation.org}] [{Chia-Leo Lin (林珈樂)}{mailto:clin@worldcubeassociation.org}] [{Ilkyoo Choi (최일규)}{mailto:ichoi@worldcubeassociation.org}] [{Ming Zheng (郑鸣)}{mailto:mzheng@worldcubeassociation.org}] [{Myagmardorj Ulziijargal (Өлзийжаргал Мягмардорж)}{mailto:mulziijargal@worldcubeassociation.org}] [{Shuhei Omura (大村周平)}{mailto:somura@worldcubeassociation.org}] [{Somya Srivastava}{mailto:ssrivastava@worldcubeassociation.org}] [{Tanai Chaikraveephand (ธนัย ชัยกระวีพันธ์)}{mailto:tchaikraveephand@worldcubeassociation.org}] [{Ujjawal Pabreja}{mailto:upabreja@worldcubeassociation.org}] [{Wilson Alvis (陈智胜)}{mailto:walvis@worldcubeassociation.org}] [{Xiaobo Jin (金晓波)}{mailto:xjin@worldcubeassociation.org}] [{Zhou Yichen (周奕臣)}{mailto:yzhou@worldcubeassociation.org}]', '[{Baiqiang Dong (董百强)}{mailto:bdong@worldcubeassociation.org}]', 'Multiple venues', 'See locations', 'See [locations](https://www.worldcubeassociation.org/competitions/FMCAsia2019#12753-locations)', NULL, 'FMC Asia 2019', 39900549, 116416645),
	('FMCEurope2020', 'FMC Europe 2020', 'Multiple cities (see website)', 'XE', '# The competition is cancelled due to the COVID-19 outbreak.\r\n### This includes all locations!\r\n\r\nThe competition will be held in multiple locations, throughout Europe. **Please pay attention to the time zone of your location!** For more details, check out the competition website!\r\n\r\nMore locations may be added until the 21st of February 2020, 23:59 UTC. If there is no location near you yet, make sure to regularly check our [website](https://fmc-europe2020.fewest-moves.com/) for new locations!', 2020, 3, 22, 2020, 3, 22, 1, '333fm', '[{Laura Ohrndorf}{mailto:lohrndorf@worldcubeassociation.org}] [{Linus Frész}{mailto:linuf95@gmail.com}] [{Sébastien Auroux}{mailto:sauroux@worldcubeassociation.org}]', '[{Laura Ohrndorf}{mailto:lohrndorf@worldcubeassociation.org}] [{Linus Frész}{mailto:linuf95@gmail.com}] [{Sébastien Auroux}{mailto:sauroux@worldcubeassociation.org}]', 'Multiple venues; [Registered locations](https://fmc-europe2020.fewest-moves.com/)', 'Multiple locations throughout Europe (see competition website)', '', 'https://fmc-europe2020.fewest-moves.com/', 'FMC Europe 2020', 50850339, 4351710),
	('FMCLatinAmerica2016', 'FMC Latin America 2016', 'Multiple cities (see website)', 'XS', 'This competition will be held in multiple countries from Latin America. For more information visit the competition website.', 2016, 1, 31, 2016, 1, 31, 0, '333fm', '[{Adrián Ramírez}{mailto:aramirez@worldcubeassociation.org}] [{Nestor Sanchez}{mailto:nestorsanchez3d@gmail.com}] [{Oscar Alberto Ceballos Contreras}{mailto:oscaralbertoceballos@gmail.com}] [{Pedro Santos Guimarães}{mailto:pguimaraes@worldcubeassociation.org}] [{Rafael de Andrade Cinoto}{mailto:rcinoto@worldcubeassociation.org}] [{Ricardo Piotti}{mailto:rpiotti@worldcubeassociation.org}]', '[{Adrián Ramírez}{mailto:aramirez@worldcubeassociation.org}] [{Luis J. Iáñez}{mailto:luisjianez@gmail.com}]', 'Multiple venues; [Registered locations](http://fmcla.cubecomps.com/2016/locations)', '(see website)', '', 'http://fmcla.cubecomps.com', 'FMC Latin America 2016', -12239264, -64632102),
	('FMCLatinAmerica2023', 'FMC Latin America 2023', 'Multiple Cities', 'XM', '*English:*\r\n\r\nThis competition will hold **only 3x3x3 Fewest Moves event**, and it will be held in multiple locations, across Latin America. Please pay attention to the **date and time zone** of your [location](https://www.worldcubeassociation.org/competitions/FMCLatinAmerica2023#24247-locations-lugares)!\r\n\r\nLocations may be added until the 25th of February 23:59UTC so if there isn\'t a location near you yet contact your local [Delegate](https://www.worldcubeassociation.org/delegates) in Latin America.\r\n\r\n---\r\n\r\n*Español:*\r\n\r\nEsta competencia tendrá **solo el evento 3x3x3 Menos Movimientos**, y se llevará a cabo en múltiples ubicaciones en América Latina. ¡Preste atención a la **fecha y zona horaria** de su [ubicación](https://www.worldcubeassociation.org/competitions/FMCLatinAmerica2023#24247-locations-lugares)!\r\n\r\nSe pueden agregar ubicaciones hasta el 25 de febrero a las 23:59 UTC, por lo que si aún no hay una ubicación cerca de usted, comuníquese con su [Delegado](https://www.worldcubeassociation.org/delegates) local en América Latina.\r\n\r\n---\r\n\r\n*Português:*\r\n\r\nEsta competição contará **apenas com a modalidade 3x3x3 Menos Movimentos** e será realizada em vários locais da América Latina. Preste atenção à **data e fuso horário** da sua [localidade](https://www.worldcubeassociation.org/competitions/FMCLatinAmerica2023#24247-locations-lugares)!\r\n\r\nOs locais podem ser adicionados até 25 de fevereiro às 23h59 UTC, portanto, se ainda não houver um local próximo a você, entre em contato com o [Delegado](https://www.worldcubeassociation.org/delegates) local na América Latina.', 2023, 3, 25, 2023, 3, 25, 0, '333fm', '[{Andrés Hisashi Suzuki Cabrera}{mailto:asuzuki@worldcubeassociation.org}] [{Areli Rubí Gordillo Martínez}{mailto:amartinez@worldcubeassociation.org}] [{Carlos Ricardo Chin Dzul}{mailto:cdzul@worldcubeassociation.org}] [{Cristian Ezequiel Vega}