	('WC2017', 'World Rubik\'s Cube Championship 2017', 'Paris', 'France', 'Please check out the website to find out about competition\'s details.', 2017, 7, 13, 2017, 7, 16, 0, '222 333 333bf 333fm 333ft 333mbf 333oh 444 444bf 555 555bf 666 777 clock minx pyram skewb sq1', '[{Hippolyte Moreau}{mailto:hmoreau@worldcubeassociation.org}] [{Jean-Louis Mathieu}{mailto:rubikfr88@gmail.com}] [{Philippe Lucien}{mailto:plucien@worldcubeassociation.org}] [{Philippe Virouleau}{mailto:pvirouleau@worldcubeassociation.org}]', '[{Antoine Piau}{mailto:apiau@worldcubeassociation.org}] [{Hippolyte Moreau}{mailto:hmoreau@worldcubeassociation.org}] [{Jean-Louis Mathieu}{mailto:rubikfr88@gmail.com}] [{Lina Tissier}{mailto:ltissier@worldcubeassociation.org}] [{Philippe Lucien}{mailto:plucien@worldcubeassociation.org}] [{Philippe Virouleau}{mailto:pvirouleau@worldcubeassociation.org}] [{Sylviane Mathieu}{mailto:layanne88@yahoo.fr}]', '[Les Docks de Paris - Dock Pullman](https://www.eurosites.fr/location-salle/eurosites-dock-paris)', 'Les Docks De Paris, 50 avenue du Président Wilson - 93200 La Plaine Saint-Denis France', 'Salle Pullman', 'http://www.rubiksworldparis2017.com', 'World Championship 2017', 48903322, 2365440),
	('WCAAfricanChampionship2022', 'Rubik\'s WCA African Championship 2022', 'Cape Town', 'South Africa', '![](https://i.imgur.com/YoWZNDt.png)\r\n\r\n**COVID-19 Safety Measures**\r\nAll registrants will be required to adhere to all COVID-19 health and safety measures while at the competition venue.\r\n\r\n**Volunteering**\r\nWe will need your help as volunteers to support with the running and judging of the day. If you would like to volunteer to help staff at the competition, please contact the [organisers](https://africanchamps.thecubinghub.com/google-forms/). Groups will be assigned so that volunteer duties don\'t clash with your competing.\r\n\r\n**Notice of Filming and Photography**\r\nAttendees of Rubik\'s WCA African Championship 2022 consent to their images being used by the World Cube Association and its partners in their marketing and social media platforms.\r\n\r\n', 2022, 10, 7, 2022, 10, 9, 0, '222 333 333bf 333fm 333mbf 333oh 444 444bf 555 555bf 666 777 clock minx pyram skewb sq1', '[{Brendan James Gray}{mailto:bgray@worldcubeassociation.org}] [{Brent Boswell}{mailto:bboswell@worldcubeassociation.org}] [{Duncan Hobbs}{mailto:dhobbs@worldcubeassociation.org}] [{Maverick Pearson}{mailto:mpearson@worldcubeassociation.org}] [{Timothy Lawrance}{mailto:tlawrance@worldcubeassociation.org}]', '[{Donovan Pretorius}{mailto:donovanp007@gmail.com}] [{Jonathan Ontong}{mailto:jsontong.jo@gmail.com}]', 'GrandWest Casino and Entertainment World', '1 Jakes Gerwel Drive, Goodwood, Cape Town, 7460', 'GrandWest Sun Exhibits Hall', 'https://africanchamps.thecubinghub.com', 'African Championship 2022', -33917704, 18547872),
	('WeareBackSofia2022', 'We are Back Sofia 2022', 'Sofia', 'Bulgaria', 'Можете да си носите храна (сандвичи или други), за да ги хапнете в зоните за релакс. Около локацията има много места, на които може да се обядва.\r\n\r\nYou can bring your own food (sandwiches or other snacks) and eat it in school canteen. There are a lot of places to eat near the Venue.', 2022, 7, 9, 2022, 7, 9, 0, '222 333 333oh 444 pyram skewb', '[{Borislav Marchovski}{mailto:bmarchovski@worldcubeassociation.org}] [{Mihai Căpăţinescu}{mailto:mcapatinescu@worldcubeassociation.org}]', '[{Borislav Marchovski}{mailto:bmarchovski@worldcubeassociation.org}] [{Plamen Mahladzhanov}{mailto:mahladjanov@abv.bg}] [{Todor Enikov}{mailto:enigma_enikov@abv.bg}]', '[Technical University of Sofia](https://tu-sofia.bg/)', 'ул. „Росарио“, 1756 София (1 Rosario street, 1756 Sofia)', 'ТУ-София, Блок 3. (Campus 3), room 3239', NULL, 'We are Back Sofia 2022', 42655591, 23353775),
	('WelcomeBackIran2022', 'Welcome Back Iran 2022', 'Tehran', 'Iran', '', 2022, 2, 18, 2022, 2, 18, 0, '222 333 333mbf 333oh pyram skewb', '[{Amir Hossein Nafisi (امیر حسین نفیسی)}{mailto:amirnafisicube@gmail.com}] [{Saeed Mostafavi Layegh (سعید مصطفوی لایق)}{mailto:slayegh@worldcubeassociation.org}]', '[{Benyamin Seddiqi (بنیامین صدیقی)}{mailto:benyaminseddighi00@gmail.com}] [{Farid Fakhrian (فرید فخریان)}{mailto:farbodksh@gmail.com}]', 'Between Boostan1 and Boostan3 street -Boostan street-Bagheri Municipality', 'between Boostan1 and Boostan3 street -Boostan street-Bagheri Municipality', '', NULL, 'Welcome Back Iran 2022', 35759511, 51202135),
	('WelcomeBackJonkoping2020', 'Welcome Back Jönköping 2020', 'Jönköping', 'Sweden', 'Välkomna tillbaka!\r\nFör första gången sedan i mars är det nu möjligt att arrangera en tävling igen.\r\nDenna tävling kommer att genomföras med en rad restriktioner för att förbygga smittorisken, läs mer om detta på de övriga flikarna.\r\n\r\n---\r\n\r\nWelcome back!\r\nFor the first time since March, we are now able to organize a competition once again.\r\nThis competition will be subject to several restrictions to prevent the risk of infection, please read more about this in the other tabs.', 2020, 9, 26, 2020, 9, 27, 0, '333 333bf 333mbf 444 444bf 555bf clock minx pyram skewb sq1', '[{Daniel Wallin}{mailto:dwallin@worldcubeassociation.org}] [{Viktor Zenk}{mailto:vzenk@worldcubeassociation.org}]', '[{Helmer Ewert}{mailto:hewert@worldcubeassociation.org}] [{Viktor Zenk}{mailto:vzenk@worldcubeassociation.org}]', '[Kulturhuset](https://kulturhusetjonkoping.se/)', 'Svavelsticksgränd 7, 553 15 Jönköping', 'The competition is in the attic, up the stairs to your left', NULL, 'Welcome Back Jönköping 2020', 57785581, 14156180),
	('WelcomeBackMongoliaChampions2020', 'Welcome Back Mongolia Championship 2020', 'Ulaanbaatar', 'Mongolia', '#### Рубик шооны Монгол улсын аварга шалгаруулах албан ёсны нээллтэй тэмцээн\r\nThis competition is the official Championship of Mongolia.\r\nOnly Mongolian citizens are eligible to win prizes and titles.\r\nThe competition remains open for all nationalities to compete.\r\n\r\n**COVID-19 цар тахлын улмаас цуцлагдсан байсан Рубик шооны улсын аварга шалгаруулах албан ёсны тэмцээн “Welcome Back Mongolia Championship 2020” гэсэн нэртэйгээр дахин зарлагдаж байна.\r\nХэрвээ та цуцлагдсан байсан Рубик шооны Улсын аварга шалгаруулах тэмцээнд бүртгүүлсэн бол энэ удаагийн тэмцээнд 50%-ийн хөнгөлөлттэй оролцох боломжтой.**\r\n\r\n**Гэхдээ та тэмцээндээ дахин бүртгүүлэх ёстой гэдгийг анхаарна уу!**\r\n\r\n**Хэрвээ та энэ удаагийн Рубик шооны улсын аварга шалгаруулах тэмцээнд оролцох боломжгүй болсон тохиолдолд таны төлсөн хураамжны мөнгийг буцаан олгох боломжгүй. Харин таньд үнэ бүхий дурсгалын зүйлс бэлэглэх болно.**\r\n\r\n**Бидний нөхцөл байдлыг ойлгож хүлээцтэй хандана уу.**\r\n\r\n\r\n**The official Mongolia Championship, which was canceled due to the COVID-19 epidemic, is being re-announced under the name \"Welcome Back Mongolia Championship 2020\".**\r\n**If you have registered for the canceled Mongolia Championship, you can participate in this competiton with a 50% discount.**\r\n\r\n**Please note, however, that you must re-register for the competition!**\r\n\r\n**If you are unable to participate in this Mongolia Championship, your fee will not be refunded. But you will get valuable souvenirs.**\r\n\r\n**Please understand our situation and be patient.**\r\n\r\n[Тэмцээнтэй холбоотой мэдээлэл/ Information of Mongolian competitions](https://www.facebook.com/Mongoliacubecompetition/)\r\n[Тэмцээнд бүртгүүлэх заавар/ Instruction of registration](https://www.facebook.com/media/set/?set=ms.c.eJxFj1EOAzAIQm~_0FMVW73~_xZSWjvy9PQBw2OJnoYQ0~%3BEAC6NqLDICriDPuB38lG~%3BUEsGcsAF~_QYKCOdkbwt9YyW4drY19jH4MhIZ~%3BSd3s7gEvAJtQPPSNV6aYbe9y8sZcQXMQs64A~-~-.bps.a.1748149085227952&type=1&__tn__=HH-R)\r\n\r\nХолбоо барих/Contact:\r\nFacebook: [Myagmardorj Ulziijargal](https://www.facebook.com/Myagmardorj.Ulziijargal)\r\n\r\nУтас/Phone:\r\n(976) 89589811 - Maralgoo Ganbold \r\n(976) 89199853 - Myagmardorj Ulziijargal', 2020, 12, 19, 2020, 12, 20, 1, '222 333 333bf 333oh 444 555 clock minx pyram skewb sq1', '[{Myagmardorj Ulziijargal (Өлзийжаргал Мягмардорж)}{mailto:mulziijargal@worldcubeassociation.org}]', '[{Maralgoo Ganbold (Ганболд Маралгоо)}{mailto:maralhello@gmail.com}] [{Sergelenbat Nymdorj}{mailto:bukgan.tamir@gmail.com}]', 'Mongolia-Japan Center', 'Mongolia-Japan Center, Baga toiruu-1, Ulaanbaatar, Mongolia', 'Conference hall, 1st floor', NULL, 'Welcome Back Mongolia 2020', 47923036, 106920334),
	('WelcomeBackNepal2022', 'Welcome Back Nepal 2022', 'Kathmandu', 'Nepal', 'The first WCA competition in Nepal in two years!\r\n\r\n**Note:** due to the COVID-19 pandemic, there are extra registration and entry requirements for this competition. Please make sure that you read and understand the [registration process](https://www.worldcubeassociation.org/competitions/WelcomeBackNepal2022#18025-registration-process-and-fees) and [COVID-19 safety protocols](https://www.worldcubeassociation.org/competitions/WelcomeBackNepal2022#18030-covid-19-safety-protocols)!', 2022, 6, 17, 2022, 6, 18, 0, '222 333 333bf 333oh 444 555 clock minx pyram skewb sq1', '[{Aayas Dhoj Joshi}{mailto:ajoshi@worldcubeassociation.org}]', '[{Abi Shrestha}{mailto:abi.stha.129@gmail.com}] [{Ankit Sanjel}{mailto:sanjelankit@gmail.com}] [{Anup Adhikari}{mailto:christ.anup103@gmail.com}] [{Saiman Adhikari}{mailto:saiman.adhikari1@gmail.com}] [{Salon Ngakhushi}{mailto:salonngakhushi@gmail.com}]', 'St. Xavier\'s College', 'Maitighar, Kathmandu', 'Fourth Floor, A-Levels Building', NULL, 'Welcome Back Nepal 2022', 27691710, 85320493),
	('WelcomeThrissur2021', 'Welcome Thrissur 2021', 'Thrissur, Kerala', 'India', '* Make sure you will be available at the venue at least 15 minutes before your event starts. You won\'t be allowed to participate in an event if you reach late.\r\n* If you\'re participating in a WCA competition for first time or not aware of competition rules, make sure that you attend the tutorial session.\r\n* If you\'re participating in a WCA competition for first time, please bring your ID card as well.\r\n\r\nAll participants are expected to volunteer for the event when they are not participating. The roles could be of a judge, runner, or a scrambler, depending upon the situation.\r\n\r\nCOVID-19 Specific Information:\r\n\r\n* We will be requiring proof of a negative COVID-19 RTPCR test within 72 hours before the start of competition or proof of full vaccination (two doses) to enter the competition.\r\n* We strongly discourage you from bringing guests. The maximum number of guests that is preferred to accompay a competitor would be limited to ONE.\r\n(Other additional guidelines will be informed in the Specific-Guidelines page).', 2021, 11, 21, 2021, 11, 21, 0, '222 333 333bf 333oh 444 pyram', '[{Daniel James}{mailto:djames@worldcubeassociation.org}]', '[{Arun Kattussery Pisharath}{mailto:arunrajeevkpsm2000@gmail.com}] [{Hariprasad CM}{mailto:hcm@worldcubeassociation.org}]', 'Loongs Cricket Academy, Aranattukara, Thrissur, Kerala, India', 'Loongs Cricket Academy, Aranattukara, Thrissur, Kerala, India,- 680618', 'Indoor Stadium', NULL, 'Welcome Thrissur 2021', 10509108, 76198392),
	('WellingtonWinter2018', 'Wellington Winter 2018', 'Wellington', 'New Zealand', 'Wellington Winter 2018 is an official World Cube Association (WCA) sanctioned speedcubing competition. Speedcubing is solving the Rubik\'s Cube or other similar puzzles as quickly as possible. The competition is open to all competitors regardless of experience and skill, but certain event-based time limits will be in place so as to make sure we can stay on schedule and get through the day on time. No prior experience in WCA competitions is necessary, but competitors should be familiar with the WCA regulations.', 2018, 7, 21, 2018, 7, 21, 0, '222 333 333oh 444 444bf 555 555bf pyram skewb', '[{Alex Asbery}{mailto:aasbery@worldcubeassociation.org}]', '[{Joshua Brungar}{mailto:joshua@jbrungar.com}]', '[ASB Sports Centre](http://wellington.govt.nz/recreation/get-active-indoors/asb-sports-centre)', '72 Kemp St, Kilbirnie, Wellington 6022, New Zealand', 'Matairangi Room', 'https://www.speedcubing.nz/event/wellington-winter-2018', 'Wellington Winter 2018', -41317968, 174801457),
	('WellspringOpen2017', 'Wellspring Open 2017', 'Ras Al Khaimah', 'United Arab Emirates', 'REMINDER:\r\nFOR COUNTRY SELECTION, FOR UAE VISA RESIDENCE, KINDLY USE HOME COUNTRY AS YOUR\r\nCOUNTRY. DON\'T USE OR REGISTER UNDER UNITED ARAB EMIRATES IF YOU ARE FROM OTHER\r\nCOUNTRIES, REGISTER THE COUNTRY MENTIONED IN YOUR PASSPORT. ONLY UAE LOCALS\r\nWILL BE ALLOWED TO USE THE UAE AS THEIR COUNTRY.\r\nE.g. If you\'re from INDIA please do not select UNITED ARAB EMIRATES', 2017, 12, 2, 2017, 12, 2, 0, '222 333 333oh 444 pyram skewb', '[{Lester Santos}{mailto:lsantos@worldcubeassociation.org}]', '[{Lester Santos}{mailto:lsantos@worldcubeassociation.org}]', 'Ras Al Khaimah Academy', '34B St - Ras al Khaimah, United Arab Emirates', 'Auditorium, Ras Al Khaimah Academy', NULL, 'Wellspring Open 2017', 25770243, 55931557),
	('WestVisayasChampionship2023', 'West Visayas Championship 2023', 'Bacolod City, Negros Occidental', 'Philippines', '#### The biggest WCA sanctioned competition in Western Visayas is here!\r\n\r\n\r\nAll necessary information about the competition can be found in the following tabs above.\r\n\r\nCompetitor or guardian must agree that NSOC, PCA, and WCA shall not be liable for any personal injury, property damage, heartbreak, or loss resulting from your participation of this event.\r\n\r\nPlease be familiar with the **[WCA rules and regulations](https://www.worldcubeassociation.org/regulations/)** before participating in this event.\r\n', 2023, 5, 27, 2023, 5, 28, 0, '222 333 333bf 333fm 333oh 444 555 666 777 clock minx pyram skewb sq1', '[{Kirby Jay Caragan}{mailto:kcaragan@worldcubeassociation.org}]', '[{Ace Djun T. Aguirre Jr.}{mailto:centrum1975@yahoo.com}] [{Bea Alexandra Marie Flores}{mailto:beaalexandramarie@gmail.com}] [{Daniel Hussain Mohammadi}{mailto:grazemohammadi@gmail.com}] [{Savion Matula}{mailto:savion37matula@gmail.com}]', '[SM City Bacolod](https://www.google.com/maps/place/SM+City+Bacolod+Northwing/@10.6722984,122.9420563,777m/data=!3m2!1e3!4b1!4m5!3m4!1s0x33aed04d351d1a59:0x9e05cac55ef55144!8m2!3d10.6722931!4d122.944245)', 'Rizal St, Reclamation Area, Bacolod City ', '3rd Floor, North Wing', NULL, 'West Visayas Championship 2023', 10670139, 122943856),
	('WienerFruhling2023', 'Wiener Frühling 2023', 'Vienna', 'Austria', '##### *English version is below*\r\n\r\n#### **Deutsch:**\r\n\r\nWir freuen uns sehr euch \"Wiener Frühling 2023\" als ein offizielles WCA Turnier ankündigen zu können. \r\n\r\nDie Speedcubing Competition wird organisiert von Pranjal Khan, Florian Truckenthanner, David Dinh, Dániel Varga und Felix Strasser und wird delegiert von Bence Barát, Emma Beranová und Viktor Kalmar. Erneut findet das Turnier im großen Saal der Akkonplatz Pfarre statt. Die Resultate dieser Competition werden zu den offiziellen WCA World Rankings hinzugefügt.\r\n\r\nJeder ist bei diesem Turnier gerne willkommen, unabhängig von der Erfahrung, Alter oder sonstigen Fähigkeiten. Manche Events haben ein spezifisches Zeitlimit, damit wir sicherstellen können den ganzen Tag über im Zeitplan zu bleiben. Es dürfen Puzzles jeder Marke verwendet werden solange sie den WCA Richtlinien entsprechen. Es sind alle Herzlich willkommen!\r\n\r\nWir freuen uns besonders auf neue Speedcuber aus Österreich!\r\n\r\n-----\r\n\r\n#### **English:**\r\n\r\nWe are happy to announce \"Wiener Frühling 2023\" as an official WCA Competition. \r\n\r\nThe speedcubing competition is organised by Pranjal Khan, Florian Truckenthanner, David Dinh, Dániel Varga, Felix Strasser and is delegated by Bence Barát, Emma Beranová and Viktor Kalmar. The results of the competition will be added to the official WCA World Rankings.\r\n\r\nThe competition is open to all competitors regardless of experience and skill, but certain event-based time limits will be in place to make sure we can stay on schedule and get through the day on time. No prior experience in WCA competitions is necessary, but competitors must be familiar with the WCA Regulations. Any puzzle brand may be used during the competition, as long as it complies with the WCA regulations.', 2023, 5, 20, 2023, 5, 21, 0, '222 333 333oh 444 555 minx pyram skewb sq1', '[{Bence Barát}{mailto:bbarat@worldcubeassociation.org}] [{Emma Beranová}{mailto:eberanova@worldcubeassociation.org}] [{Viktor Kalmar}{mailto:viktorcube@gmail.com}]', '[{Dániel Varga}{mailto:daniel.varga@icloud.com}] [{David Dinh}{mailto:dinhdhdavid@gmail.com}] [{Felix Strasser}{mailto:felix.strasser@hotmail.com}] [{Florian Truckenthanner}{mailto:vossytv@gmail.com}] [{Pranjal Khan}{mailto:pranjal.khan@hotmail.com}]', '[Großer Saal - Pfarre Akkonplatz](https://www.akkonplatz.at/index.php/de/raeume-nutzen/grossersaal)', 'Oeverseestraße 2c, 1150 Wien, Austria', 'Folgen Sie den Schildern, um den Veranstaltungsort zu betreten. / Follow the signs to enter the venue.', NULL, 'Wiener Frühling 2023', 48202129, 16316067),
	('WillimiehenKuutiopaivat2023', 'Willimiehen Kuutiopäivät 2023', 'Lappeenranta', 'Finland', 'Please read through the [regulations](https://www.worldcubeassociation.org/regulations/) before the competition.\r\nThe schedule may be subject to change, so if you\'re leaving the venue during the day, make sure to return at least 30 minutes before your scheduled events.\r\n\r\n\r\nLue säännöt ([englanniksi](https://www.worldcubeassociation.org/regulations/), [suomeksi](https://www.worldcubeassociation.org/regulations/translations/finnish/)) ennen kilpailua.\r\nAikataulu voi muuttua, joten jos poistut kisapaikalta päivän aikana, palaa vähintään 30 minuuttia ennen lajejasi.', 2023, 7, 22, 2023, 7, 23, 0, '222 333 333bf 333oh 444 444bf 555 555bf 666 777 clock pyram skewb sq1', '[{Jānis Zirnis}{mailto:jzirnis@worldcubeassociation.org}] [{Niko Ronkainen}{mailto:nronkainen@worldcubeassociation.org}] [{Olli Vikstedt}{mailto:ovikstedt@worldcubeassociation.org}] [{Timo Norrkniivilä}{mailto:tnorrkniivila@worldcubeassociation.org}]', '[{Erkka Niiva}{mailto:erkka.niiva@hotmail.com}] [{Niko Ronkainen}{mailto:nronkainen@worldcubeassociation.org}]', 'Tirilän Työväentalo', 'Onninkatu 6, 53500 Lappeenranta', '', NULL, 'Willimiehen Kuutiopäivät 2023', 61057895, 28237335),
	('WinnipegOpen2023', 'Winnipeg Open 2023', 'Winnipeg, Manitoba', 'Canada', '# FMC Canada 2023\r\n\r\nFMC Canada 2023 is also being held before Winnipeg Open 2023 at the same venue. You are welcome to register for one or both competitions, but please note that you need to *register for FMC Canada 2023 separately*.', 2023, 6, 17, 2023, 6, 18, 0, '222 333 333bf 444 777 minx pyram skewb', '[{Alexander Mutch}{mailto:amutch@worldcubeassociation.org}] [{Carter Bitz}{mailto:cbitz@worldcubeassociation.org}] [{Carter Kucala}{mailto:ckucala@worldcubeassociation.org}] [{Simon Kellum}{mailto:skellum@worldcubeassociation.org}] [{Walker Welch}{mailto:wwelch@worldcubeassociation.org}]', '[{Alberta Cubers}{mailto:albertacubers@gmail.com}] [{Alexander Mutch}{mailto:amutch@worldcubeassociation.org}] [{Laura Plourde}{mailto:lauraplourde@outlook.com}] [{Walker Welch}{mailto:wwelch@worldcubeassociation.org}]', '[Crescentwood Site - Corydon Community Centre](https://corydoncc.com/facilities/crescentwood-facilities/)', '1170 Corydon Ave, Winnipeg, MB R3M 0Z1, Canada', 'Saturday: Multi-Purpose Room, Sunday: Crescentwood Gym', NULL, 'Winnipeg Open 2023', 49864835, -97170405),
	('WinterCubeAnniversary2015', 'Winter Cube Anniversary 2015', 'Busan', 'Korea', '5000 WON for first event, 1000 WON for each additional event. 1000 WON discount for participants with previous competition\'s lanyard. Registration closes at 11:59PM on February 2nd, 2015.', 2015, 2, 7, 2015, 2, 7, 0, '333 333bf 333oh pyram skewb', '[{Ilkyoo Choi (최일규)}{mailto:ichoi@worldcubeassociation.org}]', '[{Korea Cube Culture United}{mailto:koreacubecultureunited@gmail.com}]', '[Busan Citizen\'s Hall](http://citizenhall.bisco.or.kr/)', '16, Jaseong-ro 133beon-gil, Dong-gu', '3rd floor', 'http://jinas23.cafe24.com/xe/notice/6801', 'Winter Cube Anniversary 2015', 35138896, 129065221),
	('WinterSetifOpen2019', 'Winter Setif Open 2019', 'Setif', 'Algeria', '-- **EN** --\r\nThe competition is open to everyone.\r\nTime: 8:30 AM until 6:30 PM.\r\n\r\n-- **FR** --\r\nLa competition est ouverte à tous le monde.\r\nHeure: de 8:30 AM à 6:30 PM.\r\n\r\n-- **AR** --\r\nالمسابقة مفتوحة للجميع.\r\nالوقت: من 8:30 صباحا إلى 6:30 مساء.', 2019, 12, 21, 2019, 12, 21, 0, '222 333 444 pyram', '[{Slimane Siroukane}{mailto:ssiroukane@worldcubeassociation.org}]', '[{Bouhafs Boukri}{mailto:boukribouhafs05@gmail.com}] [{Slimane Siroukane}{mailto:ssiroukane@worldcubeassociation.org}]', 'École Nationale des Sports Olympiques (ENSO)', ' 59XC + RX Setif, Algeria', '', NULL, 'Winter Setif Open 2019', 36199562, 5372437),
	('WirewoodPro2017', 'Wirewood Pro 2017', 'Montevideo', 'Uruguay', 'El dinero para la inscripción se pagará el día mismo de la competencia.', 2017, 4, 30, 2017, 4, 30, 0, '333bf 333mbf 333oh 444 555 666 777 clock minx skewb sq1', '[{Mateo Rodríguez}{mailto:mrodriguez@worldcubeassociation.org}] [{Ricardo Piotti}{mailto:rpiotti@worldcubeassociation.org}]', '[{Francisco Alonso}{mailto:franalonso2001@gmail.com}] [{Lucas Moliné}{mailto:lucas.moline03@gmail.com}]', 'Wirewood City', 'Bulevar España 2697 esquina ellauri', 'En la entrada del local', NULL, 'Wirewood Pro 2017', -34913457, -56155052),
	('WSMO2018', 'Weston-super-Mare Open 2018', 'Weston-super-Mare, Somerset', 'United Kingdom', 'Please make sure to read all the information in the tabs above.', 2018, 11, 24, 2018, 11, 25, 0, '222 333 333bf 333mbf 333oh 444 555 666 777 clock minx pyram sq1', '[{Daniel Sheppard}{mailto:danielkcsheppard@gmail.com}] [{James Molloy}{mailto:jmolloy@worldcubeassociation.org}] [{Sam Spendla}{mailto:sspendla@worldcubeassociation.org}]', '[{AJ Nicholls}{mailto:shakyhands.aj@gmail.com}] [{Bertie Longden}{mailto:blongden@worldcubeassociation.org}] [{Chris Wright}{mailto:cwwright.uk@gmail.com}]', '[Grand Pier](https://www.grandpier.co.uk/)', '179 Seafront Promenade, Weston-super-Mare BS23 1SE, UK', 'Regency Suite, Top Floor', NULL, 'Weston-super-Mare Open 2018', 51347803, -2986299),
	('XelaOpen2019', 'Xela Open 2019', 'Quetzaltenango', 'Guatemala', 'Competencia que se desarrolla por quinta vez en Quetzaltenango. Con el objetivo principal de aumentar la comunidad en esta area del pais y asi promover mas el speedcubing. \r\n\r\n\r\nCompetition that takes place for the fifth time in Quetzaltenango. With the main objective of increasing the community in this area of the country and thus promote more speedcubing.\r\n\r\nEnglish\r\n\"Competing T-shirts for those who register on the same day will be given until stocks run out. \"\r\n\r\nEspañol\r\n\"Las camisetas que compiten para aquellos que se registren el mismo día se darán hasta que las existencias se agoten\" ', 2019, 9, 7, 2019, 9, 8, 0, '222 333 333bf 333oh 444 555 666 777 clock minx pyram skewb sq1', '[{Luis David Hernández Mejía}{mailto:lmejia@worldcubeassociation.org}]', '[{Jackie Vásquez}{mailto:kakaw08@hotmail.com}] [{Pablo Say}{mailto:rubiksxela@gmail.com}]', 'Centro Cultural Casa NOJ', '7ma calle 12-12 zona 1, Quetzaltenango', 'Salón Principal', NULL, 'Xela Open 2019', 14833720, -91518972),
	('YayYarislarilBalakan2022', 'Yay Yarışları - Balakən 2022', 'Balakən', 'Azerbaijan', 'Yay Yarışları 2022 [Azərbaycan Kub Assosiasiyası](https://www.facebook.com/officialACA/) tərəfindən təşkil olunur.\r\n\r\nYay Yarışları 2022 competitions are organized by [Azerbaijan Cube Association](https://www.facebook.com/officialACA/).', 2022, 6, 15, 2022, 6, 15, 0, '333 444 pyram', '[{Javid Nabizade}{mailto:jnabizade@worldcubeassociation.org}]', '[{Javid Nabizade}{mailto:jnabizade@worldcubeassociation.org}] [{Nigar Muzaffarova}{mailto:nigar.muzaffars@gmail.com}]', 'Balakən Gənclər Evi', 'Heydər Əliyev, 143, Balakən', 'Second Floor', NULL, 'Yay Yarışları - Balakən 2022', 41702951, 46427324),
	('YerevanOpen2023', 'Yerevan Open 2023', 'Yerevan', 'Armenia', '![](https://www.worldcubeassociation.org/rails/active_storage/blobs/redirect/eyJfcmFpbHMiOnsibWVzc2FnZSI6IkJBaHBBaXd1IiwiZXhwIjpudWxsLCJwdXIiOiJibG9iX2lkIn19--04c84c02e689ba2a278a255c026d2646cdda4343/1200px-Yerevan_2012_February.jpeg)\r\n## Welcome to Yerevan!\r\nWe are so excited to announce that the next WCA approved competition in Yerevan.\r\nPlease read the tabs attentively before registering.\r\n\r\n## Բարի գալուստ Երևան!\r\nԵրևանում տեղի կունենա Ռուբիկ կուբիկի հերթական պաշտոնական առաջնությունը։\r\nԳրանցվելուց առաջ անպայման կարդալ տրամադրված տեղեկությունը։', 2023, 2, 25, 2023, 2, 25, 0, '222 333 333oh 444 555 pyram', '[{Mayis Jraghatspanyan}{mailto:mjraghatspanyan@worldcubeassociation.org}] [{Vako Marchilashvili (ვაკო მარჩილაშვილი)}{mailto:vmarchilashvili@worldcubeassociation.org}]', '[{Mayis Jraghatspanyan}{mailto:mjraghatspanyan@worldcubeassociation.org}]', '[Tumo center for creative technologies](https://tumo.org/)', '16 Halabyan St., Yerevan 0038, Armenia', 'Main entrance of the TUMO center for creative technologies', NULL, 'Yerevan Open 2023', 40196298, 44479865),
	('YJFestBelarus2018', 'YJ Fest Belarus 2018', 'Minsk', 'Belarus', 'Registration will start on 15th July and will finish on 17th August.\r\nRegistration fee and other details please see on the website.\r\n\r\nРегистрация начнётся 15 июля в 18:00 и закончится 17 августа в 23:59.\r\nСтоимость участия и другую важную информацию смотрите в группе во ВКонтакте.', 2018, 8, 25, 2018, 8, 26, 0, '222 333 333bf 333ft 333mbf 333oh 444 444bf 555 555bf clock pyram skewb', '[{Ilya Tsiareshka}{mailto:itsiareshka@worldcubeassociation.org}]', '[{Ivan Terekh}{mailto:zere_v@mail.ru}] [{Nikita Loika}{mailto:nik200896@gmail.com}] [{Olga Sarigoz}{mailto:sarigozby@gmail.com}] [{Roman Strakhov}{mailto:fpmk2@ya.ru}]', '[Palace of Children and Youth](http://mgddm.by/)', 'Starovilenskiy trakt 41', 'In the Mramorny hall on the first floor', 'https://vk.com/yjfestbelarus', 'YJ Fest Belarus 2018', 53924809, 27543818),
	('YJMalaysiaCubeOpen2022', 'YJ Malaysia Cube Open 2022', 'Petaling Jaya', 'Malaysia', 'For more information, visit [YJ Malaysia Cube Open 2022 Website](https://www.mycubeassociation.com/mco2022)\r\n\r\n**Kindly read through all tabs on this page as they contain very useful information.**', 2022, 9, 2, 2022, 9, 4, 0, '222 333 333bf 333fm 333mbf 333oh 444 444bf 555 555bf 666 777 clock minx pyram skewb sq1', '[{Hoe Zi Yang}{mailto:zhoe@worldcubeassociation.org}] [{Leow Yi Jun (廖艺畯)}{mailto:yleow@worldcubeassociation.org}] [{Wang Junwen (王俊文)}{mailto:jwang@worldcubeassociation.org}]', '[{Darren Siew Ee Yaang (蕭奕暘)}{mailto:darrensieweeyaang@gmail.com}] [{Eason Siew Ee Son (蕭奕晨)}{mailto:siew.eason@gmail.com}] [{Manfred Siew Ee Sheng (蕭奕晟)}{mailto:manfred.cubing@gmail.com}]', 'Citta Mall', '1, Jalan PJU 1a/48, Pusat Perdagangan Dana 1, 47301 Petaling Jaya, Selangor', '(S-20 to S-23) The Space, Second Floor', NULL, 'YJ Malaysia Cube Open 2022', 3112712, 101580553),
	('YJPetersburgSpecial2019', 'YJ Petersburg Special 2019', 'Kolpino, Saint Petersburg', 'Russia', 'ATTENTION! Please read \"Registration requirements\".\r\nPlease see the [website](https://vk.com/yj_special) for more information.\r\n***\r\nВНИМАНИЕ! Обратите внимание на раздел \"Требования к регистрации\" и полностью его прочитайте!\r\nДля более подробной информации заходите в нашу [группу ВКонтакте](https://vk.com/yj_special).', 2019, 4, 20, 2019, 4, 21, 0, '333bf 333fm 333ft 333mbf 444bf 555bf 666 777 clock sq1', '[{Ilya Tsiareshka}{mailto:itsiareshka@worldcubeassociation.org}]', '[{IPO \"Speedcubing Federation\" (МОО \"Федерация Спидкубинга\")}{mailto:info@cubingrf.org}] [{Serafima Petrova (Серафима Петрова)}{mailto:petrova.serafima@yandex.ru}]', '[Center for Children Technical Creativity](http://цдтт.рф)', '196655, Санкт-Петербург, г. Колпино, Тверская ул., д. 23, литера А', 'On the first floor in the Assembly Hall', 'https://vk.com/yj_special', 'YJ Petersburg Special 2019', 59740440, 30609495),
	('YongjunJakartaSpeedcubing2019', 'Yongjun Jakarta Speedcubing 2019', 'Jakarta', 'Indonesia', 'An official World Cube Association competition initiated by the [Nusantara Speedcubing Association](http://www.nsa.or.id/) and Jakarta Speedcubing Community in collaboration with [Green Pramuka Square](https://www.instagram.com/greenpramukasquarejakarta/) and [YJ](https://www.facebook.com/Yongjuncube/) to accommodate people who love the cube.', 2019, 9, 14, 2019, 9, 15, 0, '222 333 333bf 333mbf 333oh 444 pyram skewb', '[{Cendy Cahyo Rahmat}{mailto:crahmat@worldcubeassociation.org}]', '[{Yusuf Abdul Qohhar}{mailto:abdulqohharyusuf@gmail.com}]', '[Green Pramuka Square](http://www.greenpramukasquare.com/)', 'Jl. Rw. Jaya No.49, RT.16/RW.9, Rawasari, Kec. Cemp. Putih, Kota Jakarta Pusat, Daerah Khusus Ibukota Jakarta 13120', 'Main Atrium', NULL, 'Yongjun Jakarta Speedcubing 2019', -6188854, 106873852),
	('YorkCubeDay2021', 'York Cube Day 2021', 'York, Western Australia', 'Australia', '![](https://i.imgur.com/ZIPeEfV.png)\r\n\r\nThe delegates/organiser of the competition will not allow anyone to enter the venue if they are showing signs of illness and are not responsible for any illness you may contract from the competition.\r\n\r\nPlease take the time to read all the FAQ tabs, even if you have previously competed before, as there may be some restrictions that you may be unaware of.\r\n\r\n**Contact us**\r\nWe are on [Facebook](https://www.facebook.com/SpeedcubingAustralia/) and [Instagram](https://www.instagram.com/speedcubingau/)!\r\n\r\n[Speedcubing Australia Website](https://speedcubing.org.au)', 2021, 1, 10, 2021, 1, 10, 0, '222 333 333oh skewb sq1', '[{Charlie van Ooran}{mailto:cooran@worldcubeassociation.org}] [{Edward Hollingdale}{mailto:ehollingdale@worldcubeassociation.org}] [{Zak Kenny}{mailto:zkenny@worldcubeassociation.org}]', '[{Charlie van Ooran}{mailto:cooran@worldcubeassociation.org}] [{Melanie Charlesworth}{mailto:markandmel@supanet.com}] [{Speedcubing Australia}{mailto:support@speedcubing.org.au}] [{Zak Kenny}{mailto:zkenny@worldcubeassociation.org}]', '[York Town Hall](https://www.york.wa.gov.au/community/facilities/town-hall.aspx)', '81 Avon Terrace, York WA 6302', '', NULL, 'York Cube Day 2021', -31891406, 116768151),
	('YoRubik20SC2017', 'Yo Rubik 2.0 S-C 2017', 'Santa Cruz', 'Bolivia', 'Competencia limitada a **60 personas**.  \r\n\r\nCompetition limited to **60 competitors**.', 2017, 11, 4, 2017, 11, 5, 0, '222 333 333bf 333mbf 333oh 444 555 666 777 clock minx pyram skewb', '[{Cristian Franco Terrazas Flores}{mailto:cflores@worldcubeassociation.org}] [{Jorge Miguel Trigo}{mailto:jtrigo@worldcubeassociation.org}] [{Rodrigo Ugarte}{mailto:rugarte@worldcubeassociation.org}]', '[{Juvenal Nuñez}{mailto:juvenal_75619441@hotmail.com}]', 'Instalaciones Santa Cruz para todos', 'Avenida El Trompillo', 'Salon', NULL, 'Yo Rubik 2.0 S-C 2017', -17798947, -63170837),
	('YouBetterBelizeIt2023', 'You Better Belize It 2023', 'Punta Gorda, BZE', 'Belize', '**English**\r\n\r\nThis competition is recognized as an official World Cube Association competition. This is the first competition in Belize.\r\nThe competition is open to all competitors of all nationalities. Registration is available on the WCA website. No experience in WCA competitions is necessary, but competitors should be familiar with the WCA [Regulations](https://www.worldcubeassociation.org/regulations/)\r\nThe competition is free to spectators and guests.\r\n\r\n**Spanish**\r\n\r\nEsta competencia es reconocida como una competencia official de la World Cube Association. Esta es la primera competencia oficial en Belice.\r\nLa competencia es abierta a competidores de cualquier nacionalidad, El registro esta habilitado desde la página oficial de la WCA. No es necesario tener experiencia, pero los competidores deben estar conocer los [Reglamentos](https://www.worldcubeassociation.org/regulations/)\r\nEl acceso a invitados y espectadores será gratuita.\r\n', 2023, 3, 18, 2023, 3, 19, 0, '222 333 333oh 444 555 minx pyram skewb', '[{Anthony Brooks}{mailto:abrooks@worldcubeassociation.org}] [{Marvin Solano}{mailto:msolano@worldcubeassociation.org}]', '[{Kristin Wiley}{mailto:cubedcommunities@gmail.com}] [{Pablo Say}{mailto:rubiksxela@gmail.com}]', '[TCC Toledo Community College Auditorium](https://tcc.edu.bz/)', 'TCC (Toledo Community College Auditorium - 454V+3CM, Punta Gorda, BZE', 'Auditorium', NULL, 'You Better Belize It 2023', 16105212, -88806453),
	('YouOnlyNeeda3x3AZ2023', 'You Only Need a 3x3 AZ 2023', 'Phoenix, Arizona', 'USA', 'This competition is recognized as an official World Cube Association competition. Therefore, all competitors must be familiar with the [WCA Regulations](https://www.worldcubeassociation.org/regulations/). If you are new to competing, please refer to the [Competitor Responsibilities](https://www.worldcubeassociation.org/competitions/YouOnlyNeeda3x3AZ2023#20697-competitor-responsibilities) tab.\r\n\r\nJoin our [Facebook group](https://www.facebook.com/groups/380588094020424/) to hear about competitions in Arizona before they\'re announced and keep in touch with cubers in the area!', 2023, 4, 15, 2023, 4, 15, 0, '333 333bf 333mbf 333oh', '[{Ivan Vanek}{mailto:ivanek@worldcubeassociation.org}] [{Jake Roberts}{mailto:jroberts@worldcubeassociation.org}] [{Mason Langenderfer}{mailto:mlangenderfer@worldcubeassociation.org}] [{Matthew Dickman}{mailto:mdickman@worldcubeassociation.org}] [{Mia Sponseller}{mailto:msponseller@worldcubeassociation.org}]', '[{Jake Roberts}{mailto:jroberts@worldcubeassociation.org}] [{Matthew Dickman}{mailto:mdickman@worldcubeassociation.org}] [{Mia Sponseller}{mailto:msponseller@worldcubeassociation.org}] [{Shane Grogan}{mailto:shane724a@gmail.com}]', '[C. O. Greenfield Elementary School](https://az01901084.schoolwires.net/greenfield)', '7009 S. 10th St. Phoenix AZ 85042', 'Multi Purpose Room', NULL, 'You Only Need a 3x3 AZ 2023', 33381738, -112057511),
	('YRCCOpen2018', 'YRCC Open 2018', 'Chuo-ku, Saitama', 'Japan', '与野ルービックキューブサークルYRCC主催にて，公式大会「YRCCオープン2018」を開催します。2x2x2〜4x4x4キューブのほか，3x3x3目隠し，スクエア1を加えた公式競技5種目で大会を開催します。\r\nYRCC Open 2018 has events 2x2x2, 3x3x3, 4x4x4, 3x3x3 blindfolded and Square-1. We do not accept late registration and don\'t miss the registration.\r\n参加費は当日入場時にお支払いください。\r\nWe accept payment only with cash at the entrance.\r\n\r\n参加定員は100名です。\r\nCompetitors limit: 100 persons', 2018, 3, 18, 2018, 3, 18, 0, '222 333 333bf 444 sq1', '[{Yuji Suse (巣瀬雄史)}{mailto:ochamee@gmail.com}] [{Yuki Tanaka (田中悠樹)}{mailto:ytanaka@worldcubeassociation.org}]', '[{Hayato Iida (飯田颯人)}{mailto:hyt8810xkxqyre4@gmail.com}] [{Morimichi Kikuchi (菊地守道)}{mailto:kikkun419themoss@gmail.com}] [{Satoru Umetsu (梅津諭)}{mailto:silviaiyan@gmail.com}] [{Tsukasa Yokoyama (横山司)}{mailto:tukasa4580@gmail.com}] [{Yuhei Takagi (高木佑平)}{mailto:yuheitakagi710@gmail.com}]', '[与野本町コミュニティセンター (Yono-honmachi Community Center)](http://www.saitama-culture.jp/yonocom/)', '〒338-0003 埼玉県さいたま市中央区本町東3-5-43 (3-5-43, Honmachi-higashi, Chuo-ku, Saitama, Saitama)', '[多目的ルーム 大 (Multipurpose room)](http://www.saitama-culture.jp/yonocom/other.html)', NULL, 'YRCC Open 2018', 35883642, 139623671),
	('YuraSpeedcubers2017', 'Yura Speedcubers 2017', 'Arequipa', 'Peru', 'El costo de inscripción es de S/ 7.00 Soles de base y S/ 2.00 por evento, y se pagará durante el registro del torneo; incluirá Kit de participante (Polo, Certificado de Participante, Refrigerio). Habrá premios para los primeros puestos, medallas y pases para el Hotel Turístico de Yura.', 2017, 1, 14, 2017, 1, 14, 0, '222 333 333bf 333mbf 333oh 444 minx pyram skewb', '[{Natán Riggenbach}{mailto:nriggenbach@worldcubeassociation.org}]', '[{Yenny Huanqque Ccapa}{mailto:yennyhuanqqueccapa@gmail.com}]', 'Municipalidad Distrital de Yura - Auditorio (Cuarto Piso)', 'Asoc. Ciudad de Dios Zn. 3 Sector B Centro Cívico ', 'Km. 15.5 Pasando Colegio Intervida carretera Arequipa-Yura', NULL, 'Yura Speedcubers 2017', -16302236, -71623866),
	('ZagrebCubeDay2019', 'Zagreb Cube Day 2019', 'Zagreb', 'Croatia', '(HR)\r\n\r\nZagreb Cube Day 2019 je dvanaesto natjecanje po redu koje se održava u Hrvatskoj od 2011. godine. Bilo tko može sudjelovati, bez obzira na nacionalnost i\r\nstarost, no svatko mora biti upoznat s WCA Pravilnikom.\r\n\r\nNatjecanje je pod organizacijom Udruge Speedcubing Hrvatska. Kotizacija pokriva trošak organizacije i najma prostora. Mogući višak kotizacije ide u svrhu razvitka Udruge Speedcubing Hrvatska.\r\n\r\n--------------\r\n\r\n(EN)\r\n\r\nZagreb Cube Day 2019 is the 12th speedcubing competition being held in Croatia since 2011. Anyone can participate, no matter which nationality or age they are, but they need to be familiar with the WCA Regulations.\r\n\r\nThis competition is being organized by the Speedcubing Association Croatia. Registration fee covers the cost of the organization and venue rental. Any extra money goes directly to support Speedcubing Association Croatia.', 2019, 5, 12, 2019, 5, 12, 0, '222 333 333bf 333oh 444 pyram skewb', '[{Dominik Vidaković}{mailto:dvidakovic@worldcubeassociation.org}]', '[{David Vujasić}{mailto:dvujasic@worldcubeassociation.org}] [{Dominik Vidaković}{mailto:dvidakovic@worldcubeassociation.org}] [{Filip Vuković}{mailto:fvukovic@speedcubinghrvatska.hr}] [{Toni Varga}{mailto:toni.varga@gmail.com}]', '[Prva Gimnazija Zagreb](https://www.prva.hr/)', 'Avenija Dubrovnik 36, 10010, Zagreb, Hrvatska', 'Competition will be held in the main hall. / Natjecanje će biti održano u glavnoj prostoriji škole. ', NULL, 'Zagreb Cube Day 2019', 45777462, 15992121),
	('ZaragozaOpen2016', 'Zaragoza Open 2016', 'Zaragoza', 'Spain', '', 2016, 2, 6, 2016, 2, 7, 0, '222 333 333bf 333fm 333ft 333mbf 333oh 444 444bf 555 666 777 clock minx pyram skewb sq1', '[{Alexander Olleta del Molino}{mailto:alexodm.wca@gmail.com}]', '[{Sandra Novales Peláez}{mailto:sandranp2000@gmail.com}]', '[Centro civíco Santa Isabel](https://www.zaragoza.es/ciudad/centros/detalle_Centro?id=3134)', 'Avda. Santa Isabel, 100 - 50016 Zaragoza', '', 'http://asociacionrubik.es/c/ZaragozaOpen2016', 'Zaragoza Open 2016', 41666759, -830636),
	('ZaragozaOpen2023', 'Zaragoza Open 2023', 'Puebla', 'Mexico', 'Estamos muy emocionados de anunciar *Zaragoza Open 2023*  ¡El primer competencia oficial del 2023 en nuestra ciudad! \r\nEsta competencia es posible gracias al apoyo de la **Preparatoria 2 de Octubre 1968** y el **Puebla Rubik\'s Team.**\r\n\r\nEsta competencia es reconocida como una competencia oficial de la WCA. Por lo tanto, todos los competidores deben estar familiarizados y entender [el reglamento de la WCA](https://www.worldcubeassociation.org/regulations/translations/spanish-american/#2a) antes de la competencia. \r\n\r\n![](https://www.worldcubeassociation.org/rails/active_storage/blobs/redirect/eyJfcmFpbHMiOnsibWVzc2FnZSI6IkJBaHBBbGM0IiwiZXhwIjpudWxsLCJwdXIiOiJibG9iX2lkIn19--d1f46347f050fc703991f2bc01a4b8c12a067f23/zara4.png)\r\n\r\n\r\nWe are so happy to annunce *Zaragoza Open 2023*  The first official competition of this year in our city!.\r\nThis competition is possible due to support of **Preparatoria 2 de Octubre 1968** and **Puebla Rubik\'s Team**.\r\n\r\nThis competition is recognized as an official World Cube Association competition. Therefore, all competitors must be familiar with the [WCA regulations](https://www.worldcubeassociation.org/regulations/translations/spanish-american/#2a)\r\n', 2023, 6, 3, 2023, 6, 4, 0, '222 333 555 777 clock pyram sq1', '[{Jaime Tadeo Perez Cardona}{mailto:jcardona@worldcubeassociation.org}]', '[{César Mora Escobar}{mailto:punkdark98@gmail.com}] [{Miguel Ángel Cruz Hernández}{mailto:buuelqbero@gmail.com}]', 'BUAP: Preparatoria 2 de Octubre 1968', 'Calle Benito Juárez 51-B, Reserva Territorial Atlixcáyotl, Concepción Guadalupe, 72450 Puebla, Pue.', 'Cancha Techada de la preparatoria', NULL, 'Zaragoza Open 2023', 19025587, -98230439),
	('ZhuyuangangOpen2020', 'Zhuyuangang Open 2020', 'Tainan', 'Taiwan', 'Please visit the competition website for more information.', 2020, 2, 29, 2020, 3, 1, 0, '222 333 333oh 444 555 666 777 clock pyram skewb sq1', '[{Chia-Leo Lin (林珈樂)}{mailto:clin@worldcubeassociation.org}]', '[{Shao-Yu Hu (胡紹宇)}{mailto:ricky9667@gmail.com}] [{Yu-Kai Chen (陳宇楷)}{mailto:a0938939010@gmail.com}]', 'Tainan Cultural and Creative Park', 'No. 16, Sec. 2, Beimen Rd., East Dist., Tainan City, Taiwan', 'Auditorium, 4F, follow the signs.', 'https://cubing-tw.net/event/2020ZhuyuangangOpen', 'Zhuyuangang Open 2020', 22998984, 120212893),
	('ZhytomyrOpen2018', 'Zhytomyr Open 2018', 'Zhytomyr', 'Ukraine', 'Registration will be closed August, 28 or when we will reach 60 approved competitors.\r\nРеєстрацію буде закрито 28 серпня або коли кількість підтверджених учасників досягне 60.\r\n\r\nSpectators are welcome. There is no entry fee for spectators.\r\nБудемо раді бачити вас в якості глядачів. Вхід безкоштовний.', 2018, 9, 2, 2018, 9, 2, 0, '222 333 444 minx pyram skewb', '[{Roman Ostapenko (Роман Остапенко)}{mailto:rostapenko@worldcubeassociation.org}]', '[{Tetyana Kovalchuk}{mailto:tatemgold@gmail.com}]', '[Gnatyuk Art Centre](https://www.facebook.com/GnatyukArtCenter/)', '20 Velyka Berdychivska st.', 'Main hall is located on the second floor. There is a cafe in the venue where everyone can take a lunch. ', NULL, 'Zhytomyr Open 2018', 50252354, 28668138),
	('ZmigrodOpen2023', 'Żmigród Open 2023', 'Żmigród', 'Poland', 'Zapraszamy na pierwsze zawody WCA w Żmigrodzie! \r\nWydarzenie odbędzie się pod honorowym patronatem Burmistrza gminy Żmigród - Roberta Lewandowskiego!\r\n\r\n----\r\nWe invite you to the first WCA competition in Żmigród!\r\nThe competitions will be held under the honorary patronage of the Mayor of the Żmigród city - Robert Lewandowski!\r\n\r\n![](https://www.worldcubeassociation.org/rails/active_storage/blobs/redirect/eyJfcmFpbHMiOnsibWVzc2FnZSI6IkJBaHBBb1kxIiwiZXhwIjpudWxsLCJwdXIiOiJibG9iX2lkIn19--992cfb3a1c02ac70d6ab3df6cffe3a0c87912c63/zmigrod_mainpage.png)', 2023, 6, 3, 2023, 6, 4, 0, '222 333 333oh 444 555 666 777 pyram skewb', '[{Jakub Hamkało}{mailto:jhamkalo@worldcubeassociation.org}] [{Karol Zakrzewski}{mailto:kzakrzewski@worldcubeassociation.org}]', '[{Karol Zakrzewski}{mailto:kzakrzewski@worldcubeassociation.org}] [{Roksana Porucznik}{mailto:alex620362@gmail.com}]', '[Szkoła Podstawowa im. Bolesława Chrobrego w Żmigrodzie](https://spzmigrod.superszkolna.pl/)', 'Sienkiewicza 6, 55-140 Żmigród', 'Sports hall', NULL, 'Żmigród Open 2023', 51467250, 16902428),
	('ZoioffCampinas2023', 'Zoioff Campinas 2023', 'Campinas, São Paulo', 'Brazil', '## Português\r\n\r\n**Note que este campeonato possui APENAS modalidades vendadas.**\r\n\r\n* O pagamento da inscrição deve ser feito antecipadamente, todas as instruções se encontram na aba de *inscrever-se* do campeonato.\r\n* A inscrição **NÃO** será aceita até que o pagamento e o comprovante sejam enviados. Sem isso sua inscrição não será aprovada e você não poderá competir.\r\n\r\n***A inscrição só será efetivada no site da WCA após a confirmação do pagamento. Assim, as inscrições estarão limitadas aos 16 primeiros pagantes. Caso o número de inscritos exceda este limite, será usada uma lista de espera de acordo com a ordem do pagamento.***\r\n\r\n--------------------\r\n\r\n## English\r\n\r\n**Please note that this competition ONLY has blindfolded events**\r\n\r\n* The payment of the registration fee must be made in advance. All the relevant instructions can be found under the *register* tab.\r\n* The registration **WILL NOT** be accepted until the payment is done and the receipt is sent. Otherwise, your registration will not be accepted and you will not be allowed to competed at the day of the competition.\r\n\r\n***Registration will only be confirmed at the WCA website after payment confirmation. Thus, registrations will be limited to the first 16 payers. If the number of registrations exceeds this limit, a waiting list will be put in place ordered by de date of payment.***', 2023, 8, 5, 2023, 8, 6, 0, '333bf 333mbf 444bf 555bf', '[{Enzo Mattos}{mailto:emattos@worldcubeassociation.org}]', '[{Marcos Ferreira Semolini}{mailto:marcos.semolini@gmail.com}] [{Robinson Semolini}{mailto:robinsonsemolini@uol.com.br}]', '[Salas Prontas](http://salasprontas.com.br/)', 'R. Dr. Teodoro Langard, 126 - Bonfim, Campinas - SP, 13070-760', '', NULL, 'Zoioff Campinas 2023', -22899199, -47080183),
	('ZreceOpen2023', 'Zreče Open 2023', 'Zreče', 'Slovenia', '*[English]*\r\n\r\nThis competition is being organized by the Rubik klub Slovenija.\r\nIf you need any additional information, or if you would like to change your registration, please write an e-mail to the **wca.slovenia@gmail.com**.\r\n\r\nFor more information, please check the tabs!\r\n\r\n*[Slovenščina]*\r\n\r\nTekmovanje organizira Rubik klub Slovenija.\r\nČe potrebujete dodatne informacije ali če bi želeli spremeniti svojo prijavo, nam pišite na **wca.slovenia@gmail.com**.\r\n\r\nZa več informacij preverite zavihke!', 2023, 6, 17, 2023, 6, 18, 0, '222 333 333bf 444 555 666 777 clock minx sq1', '[{Jernej Omulec}{mailto:jomulec@worldcubeassociation.org}] [{Petra Kobal Vogrinec}{mailto:pvogrinec@worldcubeassociation.org}]', '[{Rubik Klub Slovenija}{mailto:wca.slovenia@gmail.com}]', '[Osnovna šola Zreče](https://www.oszrece.net/)', 'Šolska cesta 3, 3214 Zreče, Slovenia', 'Competition will be held in a gym', NULL, 'Zreče Open 2023', 46373161, 15390019),
	('ZuneOpen2012', 'Zune Open 2012', 'Namur', 'Belgium', '', 2012, 4, 28, 2012, 4, 29, 0, '222 333 333bf 333fm 333mbf 333oh 444 444bf 555 555bf magic minx mmagic pyram sq1', '[{Lars Vandenbergh}{mailto:lars@cubezone.be}]', '[{Zoé de Moffarts}{mailto:zoe.demoffarts@gmail.com}]', 'Le Chalet', '25 Rue du Cimetière, 5100 Jambes', '', 'http://dl.dropbox.com/u/23824956/Zune%20Open%20website/home.html', 'Zune Open 2012', 50456367, 4871877),
	('ZurichOpen2019', 'Zurich Open 2019', 'Uster', 'Switzerland', '', 2019, 5, 18, 2019, 5, 19, 0, '222 333 333bf 333oh 444 555 666 777 clock minx pyram skewb sq1', '[{Oleg Gritsenko}{mailto:ogritsenko@worldcubeassociation.org}] [{Tobias Peter}{mailto:tobias.peter@bluewin.ch}]', '[{Fabian Löhle}{mailto:fabian.lakers@hotmail.com}] [{Theo Mayer}{mailto:theoderkaffe@gmail.com}]', 'Musikcontainer Uster', 'Asylstrasse 10, 8610 Uster', '', NULL, 'Zurich Open 2019', 47350221, 8723703),
	('ZUSTOpen2017', 'ZUST Open 2017', 'Hangzhou, Zhejiang', 'China', 'The number limit of competitors is 160.\r\nThe registration will be opened at 19:00 15th Apr.\r\nPlease check the competition website for more information (events, schedule, etc).', 2017, 6, 10, 2017, 6, 11, 0, '222 333 333bf 333fm 333mbf 333oh 444 444bf 555 555bf clock minx pyram', '[{Baiqiang Dong (董百强)}{mailto:bdong@worldcubeassociation.org}]', '[{Junjie Fu (傅俊杰)}{mailto:864283256@qq.com}]', '[Zhejiang University of Science and Technology](http://www.zust.edu.cn/)', 'Liuhe Road, Xihu District', 'A4-122', 'https://cubingchina.com/competition/ZUST-Open-2017', 'ZUST Open 2017', 30219464, 120027330),
